import axios from "axios";
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import SimpleNavbar from "./SimpleNavbar";
import SimpleFooter from "./SimpleFooter";

function Register() {
    const navigate = useNavigate();

    const [formData, setFormData] = useState({
        name: "",
        email: "",
        dob: "",
        gender: "",
        address: "",
        phone: "",
        password: "",
        confirmPassword: ""
    });

    const [errors, setErrors] = useState({});

    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const validate = () => {
        let newErrors = {};

        if (!formData.name) newErrors.name = "Full name is required";

        if (!formData.email) {
            newErrors.email = "Email is required";
        } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
            newErrors.email = "Invalid email format";
        }

        if (!formData.dob) newErrors.dob = "Date of birth is required";
        if (!formData.gender) newErrors.gender = "Please select gender";
        if (!formData.address) newErrors.address = "Address is required";
        if (!formData.phone) newErrors.phone = "Contact number is required";

        if (!formData.password) {
            newErrors.password = "Password is required";
        } else {
            const regex = /^[A-Za-z]+@[0-9]+$/;
            if (!regex.test(formData.password)) {
                newErrors.password = "Format: letters@numbers (e.g. abc@123)";
            }
        }

        if (!formData.confirmPassword) {
            newErrors.confirmPassword = "Confirm your password";
        } else if (formData.password !== formData.confirmPassword) {
            newErrors.confirmPassword = "Passwords do not match";
        }

        return newErrors;
    };

    const handleSubmit = async (e) => {
    e.preventDefault();

    const validationErrors = validate();
    setErrors(validationErrors);

    if (Object.keys(validationErrors).length > 0) return;

    try {
        await axios.post("http://127.0.0.1:8000/signup/", {
            name: formData.name,
            email: formData.email,
             dob: formData.dob,
            gender: formData.gender,
            address: formData.address,
            phone: formData.phone,
            password: formData.password
        });

        alert("Signup Successful ✅");
        navigate("/login");

    } catch (error) {
        console.log(error);

        if (error.response && error.response.data) {
            alert(JSON.stringify(error.response.data));
        } else {
            alert("Server error or CORS issue ❌");
        }
    }
};
    return (
        <div style={styles.container}>

            {/* Navbar */}
            <SimpleNavbar />

            {/* Form Card */}
            <form style={styles.card} onSubmit={handleSubmit}>
                <h2 style={styles.title}>Create Account</h2>

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Full Name *</label>
                        <input
                            name="name"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.name ? "red" : "#ccc"
                            }}
                        />
                        {errors.name && <span style={styles.error}>{errors.name}</span>}
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Email *</label>
                        <input
                            name="email"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.email ? "red" : "#ccc"
                            }}
                        />
                        {errors.email && <span style={styles.error}>{errors.email}</span>}
                    </div>
                </div>

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Date of Birth *</label>
                        <input
                            type="date"
                            name="dob"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.dob ? "red" : "#ccc"
                            }}
                        />
                        {errors.dob && <span style={styles.error}>{errors.dob}</span>}
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Gender *</label>
                        <select
                            name="gender"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.gender ? "red" : "#ccc"
                            }}
                        >
                            <option value="">Select</option>
                            <option>Male</option>
                            <option>Female</option>
                            <option>Other</option>
                        </select>
                        {errors.gender && <span style={styles.error}>{errors.gender}</span>}
                    </div>
                </div>

                <div style={styles.inputGroup}>
                    <label>Address *</label>
                    <textarea
                        name="address"
                        onChange={handleChange}
                        style={{
                            ...styles.input,
                            borderColor: errors.address ? "red" : "#ccc"
                        }}
                    />
                    {errors.address && <span style={styles.error}>{errors.address}</span>}
                </div>

                <div style={styles.inputGroup}>
                    <label>Contact Number *</label>
                    <input
                        name="phone"
                        onChange={handleChange}
                        style={{
                            ...styles.input,
                            borderColor: errors.phone ? "red" : "#ccc"
                        }}
                    />
                    {errors.phone && <span style={styles.error}>{errors.phone}</span>}
                </div>

                <div style={styles.row}>
                    <div style={styles.inputGroup}>
                        <label>Password *</label>
                        <input
                            type="password"
                            name="password"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.password ? "red" : "#ccc"
                            }}
                        />
                        {errors.password && <span style={styles.error}>{errors.password}</span>}
                    </div>

                    <div style={styles.inputGroup}>
                        <label>Confirm Password *</label>
                        <input
                            type="password"
                            name="confirmPassword"
                            onChange={handleChange}
                            style={{
                                ...styles.input,
                                borderColor: errors.confirmPassword ? "red" : "#ccc"
                            }}
                        />
                        {errors.confirmPassword && (
                            <span style={styles.error}>{errors.confirmPassword}</span>
                        )}
                    </div>
                </div>

                <button type="submit" style={styles.button}>
                    Sign Up
                </button>

                <p style={styles.footerText}>
                    Already have an account?
                    <span style={styles.link} onClick={() => navigate("/login")}>
                        Login
                    </span>
                </p>
            </form>

            {/* Footer */}
            <SimpleFooter />
        </div>
    );
}

export default Register;

const styles = {
    container: {
        minHeight: "100vh",
        backgroundColor: "#f4f6f9",
        display: "flex",
        flexDirection: "column",
        alignItems: "center"
    },

    card: {
        width: "500px",
        background: "#fff",
        padding: "25px",
        borderRadius: "10px",
        boxShadow: "0 5px 12px rgba(0,0,0,0.1)",
        margin: "20px 0"
    },

    title: {
        textAlign: "center",
        marginBottom: "20px"
    },

    row: {
        display: "flex",
        gap: "10px"
    },

    inputGroup: {
        flex: 1,
        display: "flex",
        flexDirection: "column",
        marginBottom: "15px"
    },

    input: {
        padding: "10px",
        borderRadius: "5px",
        border: "1px solid #ccc",
        marginTop: "5px"
    },

    error: {
        color: "red",
        fontSize: "12px",
        marginTop: "3px"
    },

    button: {
        width: "100%",
        padding: "12px",
        backgroundColor: "#2c3e50",
        color: "white",
        border: "none",
        borderRadius: "5px",
        cursor: "pointer"
    },

    footerText: {
        textAlign: "center",
        marginTop: "15px"
    },

    link: {
        marginLeft: "5px",
        color: "#2c3e50",
        fontWeight: "bold",
        cursor: "pointer"
    }
};
